field.expresion:
@fan1 := (SELECT group_concat( ctafan separator '<br>')  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(@newsrc) ,'%') and trim( @newsrc) != '' )
                         and baja = 0 and length(@newsrc) > 3 )

@cuentasrccta := IFNULL((SELECT CCTCUENT.ctacod  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(@newsrc) ,'%') and trim( @newsrc) != '' )
                         and baja = 0 and length(@newsrc) > 3 ), '')

@cuentasrcsis := (SELECT CCTCUENT.siscod  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(@newsrc) ,'%') and trim( @newsrc) != '' )
                         and baja = 0 and length(@newsrc) > 3 )

@fan1 := (SELECT group_concat( ctafan separator '<br>')  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(dst) ,'%') and trim(dst) != '' )
                         and baja = 0 and length(dst) > 3 )

@cuentadstcta := (SELECT CCTCUENT.ctacod  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(dst) ,'%') and trim(dst) != '' )
                         and baja = 0 and length(dst) > 3 )

@cuentadstsis := (SELECT CCTCUENT.siscod  FROM CCTCUENT  where
                        (replace(ctatel, ' ','') like CONCAT('%' ,trim(dst) ,'%') and trim(dst) != '' )
                         and baja = 0 and length(dst) > 3 )
